```javascript
import {fetch} from 'wix-fetch';
import {getSecret} from 'wix-secrets-backend';

// Define system instructions
const SYSTEM_INSTRUCTIONS = `
You are a friendly and helpful AI assistant for a company that offers various services including DJ coverage, event coverage, film production, fire performers, music video production, behind-the-scenes coverage, and small business services. Your personality is inspired by "The Dude" from The Big Lebowski - casual and laid-back, but knowledgeable. Use words like "man," "dude," "cool," "groovy," "far out," but don't overdo it. Always be friendly and helpful.

Your main goals are:
1. Greet users and ask about their service interests
2. Provide information about services
3. Assist with booking inquiries
4. Answer questions about rates
5. Handle additional questions or direct users to speak with a human if needed

Remember to keep responses concise but informative.
`;

// Initialize conversation history
let conversationHistory = [
    {role: "system", content: SYSTEM_INSTRUCTIONS}
];

// This function would be called when a message is sent by the user
export async function handleUserMessage(userMessage) {
    try {
        const apiKey = await getSecret('OPENAI_API_KEY');

        // Add user message to conversation history
        conversationHistory.push({role: "user", content: userMessage});

        const response = await fetch('https://api.openai.com/v1/chat/completions', {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${apiKey}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                model: "gpt-3.5-turbo",
                messages: conversationHistory,
                max_tokens: 150,
                temperature: 0.7
            })
        });

        const data = await response.json();
        const botResponse = data.choices[0].message.content;

        // Add bot response to conversation history
        conversationHistory.push({role: "assistant", content: botResponse});

        // Keep conversation history to a reasonable size
        if (conversationHistory.length > 10) {
            conversationHistory = [
                conversationHistory[0],
                ...conversationHistory.slice(-9)
            ];
        }

        return botResponse;
    } catch (error) {
        console.error('Error:', error);
        return "Whoa, hit a snag there, dude. Mind trying again?";
    }
}

// Front-end code (in a page script)
$w.onReady(function () {
    $w("#sendButton").onClick(() => sendMessage());
    $w("#chatInput").onKeyPress((event) => {
        if (event.key === "Enter") {
            sendMessage();
        }
    });
});

async function sendMessage() {
    let userInput = $w("#chatInput").value;
    if (userInput.trim() !== "") {
        displayMessage("You: " + userInput);
        $w("#chatInput").value = "";
        $w("#chatInput").disable();
        $w("#sendButton").disable();

        let botResponse = await handleUserMessage(userInput);
        displayMessage("AI Dude: " + botResponse);

        $w("#chatInput").enable();
        $w("#sendButton").enable();
        $w("#chatInput").focus();
    }
}

function displayMessage(message) {
    let chatBox = $w("#chatBox");
    chatBox.text += message + "\n\n";
    chatBox.scrollTo(chatBox.scrollHeight);
}
```

This code does the following:

1. It defines system instructions that set the tone and behavior for the AI.

2. It maintains a conversation history, which helps the AI understand context.

3. The `handleUserMessage` function sends the entire conversation history to the OpenAI API, allowing for more coherent and contextually appropriate responses.

4. It manages the conversation history, keeping it to a reasonable size to avoid hitting token limits.

5. The front-end code disables the input while waiting for a response, providing better user feedback.

To use this code:

1. Place the `handleUserMessage` function and the `SYSTEM_INSTRUCTIONS` constant in a backend module (e.g., ChatBot.jsw).

2. Put the rest of the code (from `$w.onReady` onwards) in your page code.

3. Set up your OpenAI API key in Wix Secrets Manager as before.

4. Ensure you have the necessary UI elements: a text input (#chatInput), a send button (#sendButton), and a text box to display the chat (#chatBox).

Remember to adapt this code to your specific needs, handle errors appropriately, and test thoroughly before deploying to your live site. Also, be mindful of OpenAI's usage limits and costs, and ensure compliance with their policies and Wix's terms of service.

