// chat-handler.js
import wixData from 'wix-data';
import {getAIResponse} from 'backend/chatbot';
import wixChatBackend from 'wix-chat-backend';

export async function wixChatMessageReceived(message) {
    console.log("Received message:", message);

    if (!message || !message.channelId) {
        console.error("Invalid message received:", message);
        return;
    }

    const channelId = message.channelId;
    const messageText = message.text || "";
    const userId = message.userId; // Assuming the message object includes a userId

    console.log(`Processing message: ${messageText} for channel: ${channelId}`);

    // Update or create chat session in database
    await updateChatSession(userId, channelId);

    try {
        const aiResponse = await getAIResponse(messageText);
        await wixChatBackend.sendMessage(channelId, aiResponse);
    } catch (error) {
        console.error("Error processing message:", error);
        await wixChatBackend.sendMessage(channelId, "I'm sorry, I'm having trouble responding right now. Please try again later.");
    }
}

async function updateChatSession(userId, channelId) {
    try {
        // Check if a session already exists for this user
        let session = await wixData.query("ChatSessions")
            .eq("userId", userId)
            .find();

        if (session.items.length > 0) {
            // Update existing session
            await wixData.update("ChatSessions", {
                ...session.items[0],
                channelId: channelId,
                lastInteraction: new Date()
            });
        } else {
            // Create new session
            await wixData.insert("ChatSessions", {
                userId: userId,
                channelId: channelId,
                lastInteraction: new Date()
            });
        }
    } catch (error) {
        console.error("Error updating chat session:", error);
    }
}
